 1	import * as React from 'react';
 2	import { kialiStyle } from 'styles/StyleUtils';
 3	import { Dropdown, DropdownItem, DropdownList, MenuToggle, MenuToggleElement, Tooltip } from '@patternfly/react-core';
 4	import { KialiIcon } from 'config/KialiIcon';
 5	import { GlobalActions } from 'actions/GlobalActions';
 6	import { store } from 'store/ConfigStore';
 7	import { Language } from 'types/Common';
 8	import { KialiAppState } from 'store/Store';
 9	import { connect } from 'react-redux';
10	import { i18n } from 'i18n';
11	import { useKialiTranslation } from 'utils/I18nUtils';
12	
13	const iconStyle = kialiStyle({
14	  verticalAlign: '-0.25rem',
15	  $nest: {
16	    '& svg': {
17	      width: '1.5rem',
18	      height: '1.5rem'
19	    }
20	  }
21	});
22	
23	const checkStyle = kialiStyle({
24	  marginLeft: '0.5rem'
25	});
26	
27	type LanguageSwitchProps = {
28	  language: string;
29	};
30	
31	export const LanguageSwitchComponent: React.FC<LanguageSwitchProps> = ({ language }) => {
32	  const [isDropdownOpen, setIsDropdownOpen] = React.useState<boolean>(false);
33	
34	  const { t } = useKialiTranslation();
35	
36	  const languageItems: React.ReactNode[] = [
37	    <DropdownItem key="english" onClick={() => switchLanguage(Language.ENGLISH)}>
38	      <span>English</span>
39	      {language === Language.ENGLISH && <KialiIcon.Check className={checkStyle} />}
40	    </DropdownItem>,
41	
42	    <DropdownItem key="spanish" onClick={() => switchLanguage(Language.SPANISH)}>
43	      <span>Español</span>
44	      {language === Language.SPANISH && <KialiIcon.Check className={checkStyle} />}
45	    </DropdownItem>,
46	
47	    <DropdownItem key="chinese" onClick={() => switchLanguage(Language.CHINESE)}>
48	      <span>中文</span>
49	      {language === Language.CHINESE && <KialiIcon.Check className={checkStyle} />}
50	    </DropdownItem>
51	  ];
52	
53	  const switchLanguage = (language: string): void => {
54	    i18n.changeLanguage(language).then(() => store.dispatch(GlobalActions.setLanguage(language)));
55	  };
56	
57	  const onDropdownSelect = (): void => {
58	    setIsDropdownOpen(!isDropdownOpen);
59	  };
60	
61	  return (
62	    <Tooltip position="bottom" content={<>{t('Switch language')}</>} trigger="mouseenter click" exitDelay={0}>
63	      <Dropdown
64	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
65	          <MenuToggle
66	            ref={toggleRef}
67	            data-test="switch-language-button"
68	            onClick={() => setIsDropdownOpen(!isDropdownOpen)}
69	            aria-label={t('Switch language')}
70	            variant="plain"
71	            isExpanded={isDropdownOpen}
72	          >
73	            <KialiIcon.Language className={iconStyle} />
74	          </MenuToggle>
75	        )}
76	        isOpen={isDropdownOpen}
77	        popperProps={{ position: 'center' }}
78	        onOpenChange={(isOpen: boolean) => setIsDropdownOpen(isOpen)}
79	        onSelect={onDropdownSelect}
80	      >
81	        <DropdownList>{languageItems}</DropdownList>
82	      </Dropdown>
83	    </Tooltip>
84	  );
85	};
86	
87	const mapStateToProps = (state: KialiAppState): LanguageSwitchProps => {
88	  return {
89	    language: state.globalState.language
90	  };
91	};
92	
93	export const LanguageSwitch = connect(mapStateToProps)(LanguageSwitchComponent);

